为了埋点实时监控业务,简单的实现了钉钉机器人报警,钉钉开发官方文档点击 interface AlarmService &#123; Response&lt;Boolean&gt; orderSuccessAlarm(CompanyAppIdEnum companyAppIdEnum, String orderNo, OrderStatusEnum orderStatusEnum); Response&lt;Boolean&gt; orderFilterAlarm(CompanyAppIdEnum companyAppIdEnum,Long userId);&#125;public class AlarmServcieImpl implements AlarmService &#123; @Autowired RedisClient RedisClient; @Autowired ConfigUtil configUtil; private static final Log logger = LogFactory.getLog(AlarmServcieImpl.class); private static final Long expireTime = 24 * 60 * 60L; //创建机器人可获取 private static final String requestUrl = &quot;https://oapi.dingtalk.com/robot/send?access_token=xxxx&quot;; @Override public Response&lt;Boolean&gt; orderSuccessAlarm(CompanyAppIdEnum companyAppIdEnum, String orderNo, OrderStatusEnum orderStatusEnum) &#123; try &#123; if (configUtil.isServerTest()) &#123; return new Response&lt;&gt;(Boolean.FALSE); &#125; String count = RedisClient.getString(SystemConstants.ORDER_STATUS_ALARM_ROBOT, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())); if (Objects.isNull(count)) &#123; RedisClient.setString(SystemConstants.ORDER_STATUS_ALARM_ROBOT, &quot;0&quot;, expireTime, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())); &#125; dispatcher(companyAppIdEnum, Number.getNumber(Long.valueOf(RedisClient.getString(SystemConstants.ORDER_STATUS_ALARM_ROBOT, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())))), AlarmTypeEnum.ORDER_ALARM); RedisClient.incrBy(SystemConstants.ORDER_STATUS_ALARM_ROBOT, 1L, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())); &#125; catch (Exception e) &#123; e.printStackTrace(); logger.error(e.getMessage(), e); &#125; return new Response&lt;&gt;(Boolean.TRUE); &#125; @Override public Response&lt;Boolean&gt; orderFilterAlarm(CompanyAppIdEnum companyAppIdEnum,Long userId) &#123; try &#123; if (configUtil.isServerTest()) &#123; return new Response&lt;&gt;(Boolean.FALSE); &#125; String count = RedisClient.getString(SystemConstants.ORDER_FILTER_USER_ALARM_ROBOT, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())); if (Objects.isNull(count)) &#123; RedisClient.setString(SystemConstants.ORDER_FILTER_USER_ALARM_ROBOT, &quot;0&quot;, expireTime, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())); &#125; dispatcher(companyAppIdEnum, Number.getNumber(Long.valueOf(RedisClient.getString(SystemConstants.ORDER_STATUS_ALARM_ROBOT, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())))), AlarmTypeEnum.ORDER_USER_FILTER); RedisClient.incrBy(SystemConstants.ORDER_STATUS_ALARM_ROBOT, 1L, companyAppIdEnum.getCompanyId().toString(), DateUtils.getDateStr(new Date())); &#125; catch (Exception e) &#123; e.printStackTrace(); logger.error(e.getMessage(), e); &#125; return new Response&lt;&gt;(Boolean.TRUE); &#125; protected void dispatcher(CompanyAppIdEnum companyAppIdEnum, Number number, AlarmTypeEnum alarmTypeEnum) &#123; Arrays.asList(Number.values()).forEach( p -&gt; &#123; if (p.equals(number) &amp;&amp; !Number.INIT_NUMBER.equals(number)) &#123; try &#123; sendNotice(companyAppIdEnum, number, alarmTypeEnum); &#125; catch (IOException e) &#123; e.printStackTrace(); logger.error(e.getMessage(), e); &#125; return; &#125; &#125; ); &#125; public static void main(String[] args) throws IOException &#123; sendNotice(CompanyAppIdEnum.WAN_KA, Number.PRELIMINARY_WARNING, AlarmTypeEnum.ORDER_ALARM); &#125; private static void sendNotice(CompanyAppIdEnum companyAppIdEnum, Number number, AlarmTypeEnum alarmTypeEnum) throws IOException &#123; HttpClient httpclient = HttpClients.createDefault(); HttpPost httppost = new HttpPost(requestUrl); httppost.addHeader(&quot;Content-Type&quot;, &quot;application/json; charset=utf-8&quot;); String textMsg = getNotice(number, companyAppIdEnum, alarmTypeEnum); StringEntity se = new StringEntity(textMsg, &quot;utf-8&quot;); httppost.setEntity(se); HttpResponse response = httpclient.execute(httppost); if (response.getStatusLine().getStatusCode() == HttpStatus.SC_OK) &#123; String result = EntityUtils.toString(response.getEntity(), &quot;utf-8&quot;); logger.info(&quot;报警已经成功发送,机构为:&#123;&#125;,响应消息为:&#123;&#125;&quot;, companyAppIdEnum.getDesc(), result); &#125; &#125; private static String getNotice(Number number, CompanyAppIdEnum companyAppIdEnum, AlarmTypeEnum alarmTypeEnum) &#123; switch (alarmTypeEnum) &#123; case ORDER_ALARM: return &quot;&#123;
&quot; + &quot; \&quot;msgtype\&quot;: \&quot;markdown\&quot;,
&quot; + &quot; \&quot;markdown\&quot;: &#123;\&quot;title\&quot;:\&quot;推单失败报警\&quot;,
&quot; + &quot;\&quot;text\&quot;:\&quot;#### 推单失败报警 \n &quot; + companyAppIdEnum.getDesc() + &quot;推单失败已超过&quot; + number.getCount() + &quot;单&quot; + &quot;\n &gt; ![screenshot](https://note.youdao.com/yws/api/personal/file/WEB77f35c865dbd286c3baed15670e8892f?method=download&amp;shareKey=dfdd0302d114373146480ae3d4330af1)\n &gt; ######&quot; + new Date() + &quot;发布 [警告]() \&quot;
&quot; + &quot; &#125;,
&quot; + &quot; \&quot;at\&quot;: &#123;
&quot; + &quot; \&quot;atMobiles\&quot;: [
&quot; + &quot; \&quot;15168426462\&quot;&quot; + &quot; ], 
&quot; + &quot; \&quot;isAtAll\&quot;: false
&quot; + &quot; &#125;
&quot; + &quot; &#125;&quot;; case ORDER_USER_FILTER: return &quot;&#123;
&quot; + &quot; \&quot;msgtype\&quot;: \&quot;markdown\&quot;,
&quot; + &quot; \&quot;markdown\&quot;: &#123;\&quot;title\&quot;:\&quot;机构过滤报警\&quot;,
&quot; + &quot;\&quot;text\&quot;:\&quot;#### 机构过滤报警 \n &quot; + companyAppIdEnum.getDesc() + &quot;过滤失败已超过&quot; + number.getCount() + &quot;单&quot; + &quot;\n &gt; ![screenshot](https://note.youdao.com/yws/api/personal/file/WEB77f35c865dbd286c3baed15670e8892f?method=download&amp;shareKey=dfdd0302d114373146480ae3d4330af1)\n &gt; ######&quot; + new Date() + &quot;发布 [警告]() \&quot;
&quot; + &quot; &#125;,
&quot; + &quot; \&quot;at\&quot;: &#123;
&quot; + &quot; \&quot;atMobiles\&quot;: [
&quot; + &quot; \&quot;15168426462\&quot;&quot; + &quot; ], 
&quot; + &quot; \&quot;isAtAll\&quot;: false
&quot; + &quot; &#125;
&quot; + &quot; &#125;&quot;; default: break; &#125; return &quot;&quot;; &#125; public enum Number &#123; INIT_NUMBER(0L, &quot;初始&quot;), PRELIMINARY_WARNING(50L, &quot;初步警告&quot;), PRELIMINARY_WARNING_PLUS(55L, &quot;初步警告&quot;), INTERMEDIATE_WARNING(100L, &quot;中级警告&quot;), INTERMEDIATE_WARNING_PLUS(105L, &quot;中级警告&quot;), INTERMEDIATE_WARNING_PLUS_PLUS(200L, &quot;中级++警告&quot;), INTERMEDIATE_WARNING_PLUS_PLUS_PLUS(205L, &quot;中级++警告&quot;), SERIOUS_WARNING(300L, &quot;严重警告&quot;), SERIOUS_WARNING_PLUS(305L, &quot;严重警告&quot;), SERIOUS_WARNING_PLUS_PLUS(350L, &quot;严重警告&quot;), SERIOUS_WARNING_PLUS_PLUS_PLUS(400L, &quot;严重警告&quot;), SERIOUS_WARNING_PLUS_PLUS_PLUS_PLUS(500L, &quot;严重警告&quot;); private Long count; private String desc; Number(Long count, String desc) &#123; this.count = count; this.desc = desc; &#125; public Long getCount() &#123; return count; &#125; public Number setCount(Long count) &#123; this.count = count; return this; &#125; public String getDesc() &#123; return desc; &#125; public Number setDesc(String desc) &#123; this.desc = desc; return this; &#125; public static Number getNumber(Long count) &#123; Number[] number = &#123;INIT_NUMBER&#125;; Arrays.asList(Number.values()).forEach( p -&gt; &#123; if (p.getCount().equals(count)) &#123; number[0] = p; return; &#125; &#125; ); return number[0]; &#125; &#125; public enum AlarmTypeEnum &#123; ORDER_ALARM, ORDER_USER_FILTER; &#125;&#125; 按照钉钉的文档来开发,创建机器人后,即可获取Webhook地址,整个过程还是很简单的,以上只是提供了一个思路.
